const input = $input.first().json;

// Extract or compute confidence
const agentConfidence = input.confidence || 0;
const classificationConfidence = input.classification_confidence || 0;
const executionTimeMs = input.execution_time_ms || 0;

// Composite confidence: weighted average
// Agent confidence (70%) + classification confidence (20%) + time penalty (10%)
const timePenalty = executionTimeMs > 10000 ? 0.5 : executionTimeMs > 5000 ? 0.8 : 1.0;
const compositeConfidence = (agentConfidence * 0.7) + (classificationConfidence * 0.2) + (timePenalty * 0.1);

const threshold = 0.7;

return [{
  json: {
    ...input,
    composite_confidence: Math.round(compositeConfidence * 100) / 100,
    agent_confidence: agentConfidence,
    classification_confidence: classificationConfidence,
    time_penalty: timePenalty,
    below_threshold: compositeConfidence < threshold,
    threshold: threshold,
    evaluated_at: new Date().toISOString()
  }
}];

const input = $input.first().json;
const confidence = $('Calculate Confidence Score').first().json;

const auditRecord = {
  timestamp: new Date().toISOString(),
  execution_id: confidence.execution_id || $execution.id,
  agent: confidence.agent || 'unknown',
  action: confidence.action || 'unknown',
  command: (confidence.original_command || confidence.command || '').substring(0, 500),
  composite_confidence: confidence.composite_confidence,
  agent_confidence: confidence.agent_confidence,
  classification_confidence: confidence.classification_confidence,
  below_threshold: confidence.below_threshold,
  requires_approval: confidence.requires_approval || false,
  approval_reason: confidence.approval_reason || null,
  routed_to_review: confidence.below_threshold,
  execution_time_ms: confidence.execution_time_ms || 0,
  result_summary: JSON.stringify(confidence.result || {}).substring(0, 1000),
  status: confidence.below_threshold ? 'review_required' : 'completed'
};

return [{ json: auditRecord }];
